async function fetchUserInfo({ userInfoEndpoint, accessToken }) {
  if (!userInfoEndpoint || !accessToken) return null;
  const res = await fetch(userInfoEndpoint, {
    headers: { Authorization: `Bearer ${accessToken}`, Accept: "application/json" },
  });
  if (!res.ok) return null;
  return await res.json();
}

function isExpiringSoon(tokenSet, skewSec = 60) {
  if (!tokenSet?.expires_at) return false;
  return tokenSet.expires_at - nowSec() <= skewSec;
}

